// Description: Collects disk latency, consensus, and network metrics for an etcd member via Thanos Querier.
// Description: Uses executeQuery() helper with histogram_quantile for p99 latencies.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("openshift.thanos.host")
def token = hostProps.get("openshift.thanos.pass")
def port = hostProps.get("openshift.thanos.port") ?: "443"
def useSsl = (hostProps.get("openshift.thanos.ssl") ?: "true").toLowerCase() == "true"

def etcdPod = instanceProps.get("auto.etcd.pod")

if (!host || !token || !etcdPod) {
    println("leader_changes:0")
    println("proposals_committed:0")
    println("proposals_applied:0")
    println("proposals_pending:0")
    println("proposals_failed:0")
    println("wal_fsync_p99:0")
    println("backend_commit_p99:0")
    println("db_total_size:0")
    println("db_in_use_size:0")
    println("keys_total:0")
    println("peer_rtt_p99:0")
    println("peer_sent_bytes:0")
    println("peer_received_bytes:0")
    return 0
}

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def executeQuery(String promql, String baseUrl, String token) {
    try {
        def encoded = java.net.URLEncoder.encode(promql, "UTF-8")
        def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Bearer ${token}")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)

        if (conn.responseCode == 200) {
            def response = conn.inputStream.text
            def json = new JsonSlurper().parseText(response)
            if (json.status == "success" && json.data?.result?.size() > 0) {
                def val = json.data.result[0].value[1]
                return val?.toString()?.isNumber() ? val : null
            }
        } else {
            System.err.println("Query failed: HTTP ${conn.responseCode} for: ${promql}")
        }
    } catch (Exception e) {
        System.err.println("Query error for ${promql}: ${e.message}")
    }
    return null
}

def results = [
    "leader_changes": 0,
    "proposals_committed": 0,
    "proposals_applied": 0,
    "proposals_pending": 0,
    "proposals_failed": 0,
    "wal_fsync_p99": 0,
    "backend_commit_p99": 0,
    "db_total_size": 0,
    "db_in_use_size": 0,
    "keys_total": 0,
    "peer_rtt_p99": 0,
    "peer_sent_bytes": 0,
    "peer_received_bytes": 0
]

def metrics = [
    "leader_changes": 'rate(etcd_server_leader_changes_seen_total{pod="' + etcdPod + '"}[5m])',
    "proposals_committed": 'rate(etcd_server_proposals_committed_total{pod="' + etcdPod + '"}[5m])',
    "proposals_applied": 'rate(etcd_server_proposals_applied_total{pod="' + etcdPod + '"}[5m])',
    "proposals_pending": 'etcd_server_proposals_pending{pod="' + etcdPod + '"}',
    "proposals_failed": 'rate(etcd_server_proposals_failed_total{pod="' + etcdPod + '"}[5m])',
    "wal_fsync_p99": 'histogram_quantile(0.99, rate(etcd_disk_wal_fsync_duration_seconds_bucket{pod="' + etcdPod + '"}[5m]))',
    "backend_commit_p99": 'histogram_quantile(0.99, rate(etcd_disk_backend_commit_duration_seconds_bucket{pod="' + etcdPod + '"}[5m]))',
    "db_total_size": 'etcd_mvcc_db_total_size_in_bytes{pod="' + etcdPod + '"}',
    "db_in_use_size": 'etcd_mvcc_db_total_size_in_use_in_bytes{pod="' + etcdPod + '"}',
    "keys_total": 'etcd_debugging_mvcc_keys_total{pod="' + etcdPod + '"}',
    "peer_rtt_p99": 'histogram_quantile(0.99, sum(rate(etcd_network_peer_round_trip_time_seconds_bucket{pod="' + etcdPod + '"}[5m])) by (le))',
    "peer_sent_bytes": 'sum(rate(etcd_network_peer_sent_bytes_total{pod="' + etcdPod + '"}[5m]))',
    "peer_received_bytes": 'sum(rate(etcd_network_peer_received_bytes_total{pod="' + etcdPod + '"}[5m]))'
]

// Histogram quantile results are in seconds; convert to milliseconds
def msMultipliers = ["wal_fsync_p99", "backend_commit_p99", "peer_rtt_p99"] as Set

metrics.each { dp, query ->
    def val = executeQuery(query, baseUrl, token)
    if (val != null) {
        def dval = val as Double
        results[dp] = msMultipliers.contains(dp) ? dval * 1000 : dval
    }
}

results.each { k, v -> println("${k}:${v}") }
return 0
